<?php

namespace App\Services;

use Ramsey\Uuid\Uuid;

class BlockJsonService
{
    /**
     * Génère le manifest.json du behavior pack.
     */
    public function behaviorManifest(string $name): array
    {
        return [
            'format_version' => '1.0.0',
            'header' => [
                'name'        => $name . ' Behavior Pack',
                'version'     => '1.0.0',
                'description' => 'Behavior pack generated by Minecraft Block Generator',
            ],
            'metadata' => [
                'authors' => ['Minecraft Block Generator'],
            ],
        ];
    }

    /**
     * Génère le manifest.json du resource pack.
     */
    public function resourceManifest(string $name): array
    {
        return [
            'format_version' => 2,
            'metadata' => [
                'authors' => ['Minecraft Block Generator'],
            ],
            'header' => [
                'name'               => $name . ' Resource Pack',
                'description'        => 'Resource pack generated by Minecraft Block Generator',
                'uuid'               => Uuid::uuid4()->toString(),
                'version'            => [1, 0, 0],
                'min_engine_version' => [1, 21, 80],
            ],
            'modules' => [
                [
                    'type'    => 'resources',
                    'uuid'    => Uuid::uuid4()->toString(),
                    'version' => [1, 0, 0],
                ],
            ],
        ];
    }

    /**
     * Génère le fichier de comportement du bloc (behavior pack).
     */
    public function blockBehavior(string $identifier, bool $solid, bool $destructible, float $resistance, string $geometry = 'cube'): array
    {
        if ($geometry === 'net') {
            // Per-face textures from split net
            $materials = [
                'up'    => ['texture' => $identifier . '_top',    'render_method' => 'opaque'],
                'down'  => ['texture' => $identifier . '_bottom', 'render_method' => 'opaque'],
                'north' => ['texture' => $identifier . '_front',  'render_method' => 'opaque'],
                'south' => ['texture' => $identifier . '_back',   'render_method' => 'opaque'],
                'east'  => ['texture' => $identifier . '_right',  'render_method' => 'opaque'],
                'west'  => ['texture' => $identifier . '_left',   'render_method' => 'opaque'],
            ];
        } else {
            $renderMethod = $geometry === 'cross' ? 'alpha_test' : 'opaque';
            $materials = ['*' => ['texture' => $identifier, 'render_method' => $renderMethod]];
        }

        $components = [
            'minecraft:material_instances' => ['materials' => $materials],
            'minecraft:friction'             => 0.6,
            'minecraft:explosion_resistance' => $resistance,
        ];

        if ($geometry !== 'cube') {
            $components['minecraft:geometry'] = [
                'identifier' => 'geometry.' . $identifier,
            ];

            $box = $this->geometryBox($geometry);
            $components['minecraft:collision_box'] = $box ?? false;
            $components['minecraft:selection_box'] = $box ?? false;
        }

        if ($destructible) {
            $components['minecraft:destructible_by_mining'] = [
                'hardness' => max(0.05, $resistance / 20),
            ];
        }

        if (!$solid) {
            $components['minecraft:collision_box'] = false;
            $components['minecraft:selection_box'] = false;
        }

        return [
            'format_version' => '1.0.0',
            'minecraft:block' => [
                'description' => [
                    'identifier' => 'custom:' . $identifier,
                ],
                'components' => $components,
            ],
        ];
    }

    /**
     * Retourne la collision/selection box pour une forme donnée, ou null si aucune.
     */
    private function geometryBox(string $geometry): ?array
    {
        return match ($geometry) {
            'slab'   => ['origin' => [-8, 0, -8], 'size' => [16, 8, 16]],
            'plate'  => ['origin' => [-8, 0, -8], 'size' => [16, 2, 16]],
            'pillar' => ['origin' => [-2, 0, -2], 'size' => [4, 16, 4]],
            'cross'  => null,
            default  => null,
        };
    }

    /**
     * Génère le fichier de géométrie (.geo.json) pour une forme non-cubique.
     * Retourne un tableau vide si la forme est 'cube' (pas de géométrie nécessaire).
     */
    public function geometryJson(string $identifier, string $geometry): array
    {
        return match ($geometry) {
            'slab'   => $this->slabGeometry($identifier),
            'plate'  => $this->plateGeometry($identifier),
            'cross'  => $this->crossGeometry($identifier),
            'pillar' => $this->pillarGeometry($identifier),
            default  => [],
        };
    }

