    /**
     * Génère le terrain_texture.json du resource pack.
     */
    public function terrainTexture(string $identifier, string $geometry = 'cube'): array
    {
        if ($geometry === 'net') {
            $textureData = [];
            foreach (['top', 'bottom', 'front', 'back', 'left', 'right'] as $face) {
                $textureData["{$identifier}_{$face}"] = [
                    'textures' => "textures/blocks/{$identifier}_{$face}",
                ];
            }
        } else {
            $textureData = [
                $identifier => ['textures' => 'textures/blocks/' . $identifier],
            ];
        }

        return [
            'num_mip_levels'     => 4,
            'padding'            => 8,
            'resource_pack_name' => 'custom_blocks',
            'texture_name'       => 'atlas.terrain',
            'texture_data'       => $textureData,
        ];
    }

    /**
     * Génère le blocks.json du resource pack.
     */
    public function blocksJson(string $identifier): array
    {
        return [
            'format_version'        => '1.21.40',
            'custom:' . $identifier => [
                'sound'    => 'stone',
                'textures' => $identifier,
            ],
        ];
    }

    /**
     * Génère le contenu du fichier texts/en_US.lang.
     */
    public function textsLang(string $identifier, string $name): string
    {
        return "tile.custom:{$identifier}.name={$name}\n";
    }

    /**
     * Génère le languages.json du resource pack.
     */
    public function languagesJson(): array
    {
        return ['en_US'];
    }

    /**
     * Encode proprement en JSON (pretty print, unicode non échappé).
     */
    public function encode(array $data): string
    {
        return json_encode($data, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
    }
}
